import React from 'react';

function Experience({ data }) {
  if (!data) return null;

  return (
    <section id="experience" className="py-12 md:py-16 bg-white">
      <div className="max-w-2xl mx-auto px-4">
        <div className="bg-white rounded-2xl shadow-lg p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Experience</h2>
          <div className="space-y-6">
            {data.map((exp, index) => (
              <div key={exp.id} className="pb-6 border-b border-gray-200 last:border-b-0">
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 bg-gradient-to-br from-blue-400 to-blue-600 rounded-lg flex items-center justify-center text-white font-bold flex-shrink-0">
                    💼
                  </div>
                  <div className="flex-1">
                    <h3 className="text-lg font-bold text-gray-900">{exp.position}</h3>
                    <p className="text-blue-600 font-semibold">{exp.company}</p>
                    <p className="text-sm text-gray-500 mt-1">{exp.period}</p>
                    <ul className="mt-3 space-y-2">
                      {exp.description.map((item, idx) => (
                        <li key={idx} className="text-sm text-gray-700 flex gap-2">
                          <span className="text-blue-600 mt-1">▸</span>
                          <span>{item}</span>
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Experience;
